class Solution:
    def solve(self, ops: List[List[str]]) -> List[int):
        ans = []; max_val, min_val = float('-inf'), float('inf');
        for op in ops:
            if op[0] == "push":
                ans.append(int(op[1])); max_val = max(max_val, int(op[1])); min_val = min(min_val, int(op[1]));
            elif op[0] == "pop":
                if ans:
                    ans.pop();
                    if max_val == ans[-1]: max_val = float('-inf');
                    if min_val == ans[-1]: min_val = float('inf');
            elif op[0] == "max": print(max_val if ans else -1);
            elif op[0] == "min": print(min_val if ans else -1);
        return [len(ans) for _ in range(len(ops))];
